VALUES
  ('diplomatic-8a96f9fb-moex-00242', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-113-c655adf3', 'sub-diplomatic-8a96f9fb-05', NULL, 'single_choice', '民粹主義是一種特別的政治現象。下列何者不屬於民粹主義式政治人物的特徵？', '["常常把人們分成菁英和一般人兩大類", "反對多元主義，認為社會上的意見都可以收攏，不存在太多不同的意見", "宣稱自己代表一般人，要打倒政治或者經濟上的優勢族群，認定這些優勢族群都對自己的群體不利", "民粹式的政客通常都具有極右翼的意識型態，通常會非常排外"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:50+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
  ('diplomatic-8a96f9fb-moex-00243', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-113-c655adf3', 'sub-diplomatic-8a96f9fb-05', NULL, 'single_choice', '在議會內閣制的國家當中，通常反對黨會指派國會議員擔任特定議題領域的監督者，這些人也會是將 來取得執政權後的內閣成員，這個團隊稱為：', '["專業議員", "監督委員會", "影子內閣", "後排議員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:50+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
  ('diplomatic-8a96f9fb-moex-00244', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-113-c655adf3', 'sub-diplomatic-8a96f9fb-05', NULL, 'single_choice', '關於「民主鞏固」，下列何者錯誤？', '["基本定義是指一個國家民主化之後，幾乎不再有倒退回威權政治的可能性", "杭廷頓認為，當一個國家的政權完成至少兩次政黨輪替後，就可以稱得上民主鞏固", "當人們都能夠接受民主的遊戲規則，沒有人挑戰民主的正當性，就可以稱得上民主鞏固", "只要達成民主鞏固的要件，就不會再有民主倒退的可能性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:50+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
  ('diplomatic-8a96f9fb-moex-00245', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-113-c655adf3', 'sub-diplomatic-8a96f9fb-05', NULL, 'single_choice', '拉丁美洲國家有很多和美國一樣採用總統制，但為什麼總統制在拉美的運行沒有像美國一樣順利？下 列何者是可能的原因？', '["拉美國家的人們在文化上比較傾向監督制衡，不喜歡讓總統掌握太多權力", "拉美國家的政黨體系偏向多黨制，讓總統制的運行較困難", "拉美國家受美國影響太深，常被美國惡意干預內政，所以總統制運作不好", "拉美國家的國會太過強勢，讓行政權常常無法做事"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:50+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
  ('diplomatic-8a96f9fb-moex-00246', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-113-c655adf3', 'sub-diplomatic-8a96f9fb-05', NULL, 'single_choice', '歐洲「極右派」政黨近期不斷興起，他們最大的共通特色不包括那一項？', '["對歐盟抱持懷疑態度", "反外來移民", "對中國及俄國抱持友好態度", "社會議題意識型態屬於極端的保守派"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:50+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
  ('diplomatic-8a96f9fb-moex-00247', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-113-c655adf3', 'sub-diplomatic-8a96f9fb-05', NULL, 'single_choice', '在國家發展的過程中，可能面臨成長到一定程度就上不去的「中度所得陷阱」難題，下列何者不是其 可能的原因？', '["投資不足，創新不足", "工資上漲，利潤降低", "受到國際政經結構的影響", "針對弱勢群體的補助太多，社福預算太高"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:50+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
  ('diplomatic-8a96f9fb-moex-00248', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-113-c655adf3', 'sub-diplomatic-8a96f9fb-05', NULL, 'single_choice', '民主轉型從發起行為者來看，可以分成「由上而下」或者「由下而上」的兩種方向。由上而下式的民 主轉型（例如墨西哥與臺灣）所帶來的優缺點，下列何者錯誤？', '["寧靜革命，較能避免大規模衝突", "充滿妥協，但也往往無法處理轉型正義的問題", "舊政權下的菁英往往可以透過制定有利的規則來延續政治生命", "族群衝突程度較高，政治手段往往成為迫害政敵的工具"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:50+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
  ('diplomatic-8a96f9fb-moex-00249', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-113-c655adf3', 'sub-diplomatic-8a96f9fb-05', NULL, 'single_choice', '非歐盟成員國欲申請加入歐盟，最重要的前提要件不包括：', '["必須要使用歐元", "必須具備民主自由的政治體制", "必須承認歐盟法律", "必須是主權獨立的國家"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:50+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
  ('diplomatic-8a96f9fb-moex-00250', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-113-c655adf3', 'sub-diplomatic-8a96f9fb-05', NULL, 'single_choice', '很多威權國家也都和民主國家一樣具有選舉（例如俄國）。下列何者不是這類選舉的特色？', '["選舉制度存在，但非公平競爭", "執政黨往往會利用各種方式阻礙在野黨的選舉競爭，例如法律手段", "選舉結果的不確定性很高，在野黨往往可以利用選舉來獲得政治權力", "選舉常被獨裁者用來裝飾自己統治的正當性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:50+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL),
  ('diplomatic-8a96f9fb-moex-00251', 'diplomatic-8a96f9fb', 'diplomatic-8a96f9fb-moex-113-c655adf3', 'sub-diplomatic-8a96f9fb-05', NULL, 'single_choice', '最高法院（憲法法院）通常是一個國家在法律上的最高裁決者。關於美國最高法院的敘述，下列何者 錯誤？', '["大法官為終身職，目的是為了讓他們盡量公正、客觀、獨立審判", "目前大法官的意識型態分布為自由派六席，保守派三席", "川普總統任期內（2017-2020年）任命了三位大法官", "大法官的任命案需要經過參議院的審核及同意"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:50+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-俄文組"}'::jsonb, NULL)
